namespace sv_8f53ea2a7c5f4b15ab9f2973a940096e.Services;

/// <summary>
/// Scoped service that holds wizard data for a single applicant.
/// In Interactive Server mode, scoped = per-circuit, so the data
/// persists across enhanced navigations between wizard pages.
/// </summary>
public class WizardState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<JobEntry> Jobs { get; set; } = [new()];
    public List<ReferenceContact> References { get; set; } = [new()];
    public HashSet<int> CompletedSteps { get; } = [];

    public event Action? OnChange;

    public void CompleteStep(int step)
    {
        CompletedSteps.Add(step);
        OnChange?.Invoke();
    }
}

@inject WizardState Wizard
@inject NavigationManager Nav
@implements IDisposable

@{
    var currentStep = GetCurrentStep();
}

<nav class="wizard-progress" aria-label="Application progress">
    @for (int i = 0; i < Steps.Length; i++)
    {
        var step = i + 1;
        var (path, label) = Steps[i];
        var isCurrent = step == currentStep;
        var isCompleted = Wizard.CompletedSteps.Contains(step) && !isCurrent;
        var cssClass = isCurrent ? "active" : isCompleted ? "completed" : "";

        <a href="@path" class="wizard-step @cssClass"
           aria-current="@(isCurrent ? "step" : null)">
            <span class="step-number">@(isCompleted ? "✓" : step)</span>
            <span class="step-label">@label</span>
        </a>

        if (i < Steps.Length - 1)
        {
            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
        }
    }
</nav>
<div class="step-indicator">Step @currentStep of @Steps.Length</div>

@code {
    private static readonly (string Path, string Label)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review")
    ];

    private Action? _stateHandler;

    protected override void OnInitialized()
    {
        Nav.LocationChanged += OnLocationChanged;
        _stateHandler = () => InvokeAsync(StateHasChanged);
        Wizard.OnChange += _stateHandler;
    }

    private void OnLocationChanged(object? sender, LocationChangedEventArgs e)
    {
        InvokeAsync(StateHasChanged);
    }

    private int GetCurrentStep()
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimStart('/');
        for (int i = 0; i < Steps.Length; i++)
        {
            if (uri.StartsWith(Steps[i].Path.TrimStart('/'), StringComparison.OrdinalIgnoreCase))
                return i + 1;
        }
        return 1;
    }

    public void Dispose()
    {
        Nav.LocationChanged -= OnLocationChanged;
        if (_stateHandler is not null)
            Wizard.OnChange -= _stateHandler;
    }
}

