@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Personal Info — Application</PageTitle>

<h1>Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="Wizard.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Experience — Application</PageTitle>

<h1>Work Experience</h1>

@for (int i = 0; i < Wizard.Jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Job @(index + 1)</h6>
                @if (Wizard.Jobs.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger"
                            @onclick="() => RemoveJob(index)">Remove</button>
                }
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="Wizard.Jobs[index].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="Wizard.Jobs[index].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="Wizard.Jobs[index].Duration"
                       placeholder="e.g. 2 years" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Previous">← Previous</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddJob() => Wizard.Jobs.Add(new());

    private void RemoveJob(int index) => Wizard.Jobs.RemoveAt(index);

    private void Previous() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

