@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>References — Application</PageTitle>

<h1>References</h1>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (Wizard.References.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger"
                            @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>
            <div class="mb-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="Wizard.References[index].Name" />
            </div>
            <div class="mb-2">
                <label class="form-label">Email</label>
                <input type="email" class="form-control"
                       @bind="Wizard.References[index].Email" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="Wizard.References[index].Relationship"
                       placeholder="e.g. Former Manager" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Previous">← Previous</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddReference() => Wizard.References.Add(new());

    private void RemoveReference(int index) => Wizard.References.RemoveAt(index);

    private void Previous() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.CompleteStep(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Review — Application</PageTitle>

<h1>Review Your Application</h1>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        <p><strong>Name:</strong> @Wizard.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @Wizard.PersonalInfo.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work Experience</strong>
        <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @foreach (var job in Wizard.Jobs)
        {
            <div class="mb-2">
                <strong>@job.Title</strong> at @job.Company
                <span class="text-muted">(@job.Duration)</span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @foreach (var reference in Wizard.References)
        {
            <div class="mb-2">
                <strong>@reference.Name</strong> — @reference.Relationship
                <span class="text-muted">(@reference.Email)</span>
            </div>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Previous">← Previous</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private void Previous() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.CompleteStep(4);
        // TODO: send data to your API / database
        Nav.NavigateTo("/");
    }
}

